+  // C2 - ((C1 - X) & M) --> X & N
+  // Pattern: C2 - (and (sub nuw C1, X), M)
+  // Valid when: C2 = C1 & M, C1 - C2 is a "low mask" (all 1s below some bit),
+  //             M = ~LowMask (negation of the low mask),
+  //             and the nuw flag on (C1 - X) ensures X <= C1.
+  // Example: 64 - ((71 - X) & -8) --> X & 120
+  //   where 71 = 64 + 7, -8 = ~7 (low 3 bits), 120 = 64 | (7 << 3)
+  {
+    const APInt *C2AP, *Mask;
+    Value *X;
+    const APInt *C1AP;
+    if (match(Op0, m_APInt(C2AP)) &&
+        match(Op1, m_OneUse(m_And(m_OneUse(m_NUWSub(m_APInt(C1AP), m_Value(X))),
+                                  m_APInt(Mask))))) {
+      // Check C2 = C1 & M
+      if (*C2AP == (*C1AP & *Mask)) {
+        APInt LowMask = *C1AP - *C2AP;
+        // Check that LowMask is all 1s (a proper low mask)
+        if (LowMask.isMask()) {
+          // Check that M = ~LowMask (M is the negation of the low mask)
+          if (*Mask == ~LowMask) {
+            unsigned k = LowMask.getBitWidth() - LowMask.countLeadingZeros();
+            // Compute result mask N = C2 | (LowMask << k)
+            APInt N = *C2AP | (LowMask << k);
+            return BinaryOperator::CreateAnd(X, ConstantInt::get(I.getType(), N));
+          }
+        }
+      }
+    }
+  }
